sp_widget.script:
(function() {
    // 1. Get the logged-in user's information
    var userId = gs.getUserID();
    var isDoctor = gs.hasRole('x_1954503_smartc_0.doctor');
    var isNurse = gs.hasRole('x_1954503_smartc_0.nurse');

    // 2. Validate authorization
    data.isAuthorized = false;
    if (isDoctor || isNurse) {
        data.isAuthorized = true;
        data.userRoleName = isDoctor ? 'Doctor' : 'Nurse';
    } else {
        return; // Early exit
    }

    data.metrics = [];

    // 3. Define all metrics based on your exact choice list
    var statsToCount = [
        { label: 'Total Assigned Patients', query: '', icon: 'fa fa-users', color: 'primary' },
        { label: 'Registered', query: "state=register", icon: 'fa fa-id-card-o', color: 'gray' },
        { label: 'Triage', query: "state=triage", icon: 'fa fa-heartbeat', color: 'purple' },
        { label: 'Waiting', query: "state=waiting", icon: 'fa fa-clock-o', color: 'orange' },
        { label: 'Consultation', query: "state=consultation", icon: 'fa fa-user-md', color: 'teal' },
        { label: 'Testing', query: "state=testing", icon: 'fa fa-flask', color: 'indigo' },
        { label: 'Admitted', query: "state=admitted", icon: 'fa fa-bed', color: 'blue' },
        { label: 'Treatment', query: "state=treatment", icon: 'fa fa-medkit', color: 'pink' },
        { label: 'Discharge Requested', query: "state=discharge_requested", icon: 'fa fa-file-text-o', color: 'yellow' },
        { label: 'Billing Pending', query: "state=billing_pending", icon: 'fa fa-hourglass-half', color: 'orange' },
        { label: 'Billing Issue', query: "state=billing_issue", icon: 'fa fa-exclamation-circle', color: 'danger' },
        { label: 'Discharged', query: "state=discharged", icon: 'fa fa-check-square-o', color: 'green' }
    ];

    // 4. Build and execute scoped aggregate queries for each metric card
    for (var i = 0; i < statsToCount.length; i++) {
        var stat = statsToCount[i];
        var ga = new GlideAggregate('x_1954503_smartc_0_patient');

        // Correct way to get a total count in ServiceNow
        ga.addAggregate('COUNT');

        // Apply dynamic scoping to the current user's assignments
        if (isDoctor) {
            ga.addQuery('assigned_doctor', userId);
        } else if (isNurse) {
            ga.addQuery('u_assigned_nurse', userId);
        }

        // Add specific condition for the individual metric
        if (stat.query) {
            ga.addEncodedQuery(stat.query);
        }

        ga.query();
        var countResult = 0;
        if (ga.next()) {
            countResult = ga.getAggregate('COUNT') || 0;
        }

        data.metrics.push({
            label: stat.label,
            value: countResult,
            icon: stat.icon,
            color: stat.color
        });
    }

})();
